import{_ as e,c as o,o as t,a1 as n}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"고급: AI 워크플로우 | oh-my-opencode","description":"oh-my-opencode의 고급 AI 워크플로우 오케스트레이션을 마스터하세요. 에이전트 팀, 병렬 작업, 카테고리/스킬 시스템, 수명 주기 훅 및 심층 사용자 정의를 배워 효율적인 AI 기반 개발 시스템을 구축하세요.","frontmatter":{"title":"고급: AI 워크플로우 | oh-my-opencode","sidebarTitle":"팀처럼 작업하기","subtitle":"고급: AI 워크플로우","description":"oh-my-opencode의 고급 AI 워크플로우 오케스트레이션을 마스터하세요. 에이전트 팀, 병렬 작업, 카테고리/스킬 시스템, 수명 주기 훅 및 심층 사용자 정의를 배워 효율적인 AI 기반 개발 시스템을 구축하세요.","order":60},"headers":[],"relativePath":"ko/code-yeongyu/oh-my-opencode/advanced/index.md","filePath":"ko/code-yeongyu/oh-my-opencode/advanced/index.md"}'),s={name:"ko/code-yeongyu/oh-my-opencode/advanced/index.md"};function i(r,a,l,d,p,h){return t(),o("div",null,[...a[0]||(a[0]=[n(`<h1 id="고급" tabindex="-1">고급 <a class="header-anchor" href="#고급" aria-label="Permalink to &quot;고급&quot;">​</a></h1><p>이 장에서는 oh-my-opencode의 고급 기능을 깊이 다룹니다: 전문 AI 에이전트 팀, 병렬 백그라운드 작업, 카테고리 및 스킬 시스템, 수명 주기 훅 등을 포함합니다. 이러한 기능을 마스터하면 실제 팀을 관리하는 것처럼 AI 워크플로우를 조율하여 더 효율적인 개발 경험을 달성할 수 있습니다.</p><h2 id="장-내용" tabindex="-1">장 내용 <a class="header-anchor" href="#장-내용" aria-label="Permalink to &quot;장 내용&quot;">​</a></h2><div class="grid-cards"><h3 id="ai-에이전트-팀-10명의-전문가-개요" tabindex="-1"><a href="./ai-agents-overview/">AI 에이전트 팀: 10명의 전문가 개요</a> <a class="header-anchor" href="#ai-에이전트-팀-10명의-전문가-개요" aria-label="Permalink to &quot;[AI 에이전트 팀: 10명의 전문가 개요](./ai-agents-overview/)&quot;">​</a></h3><p>10개의 내장 에이전트 기능, 사용 사례, 호출 방법을 포괄적으로 소개합니다. 작업 유형에 따라 적절한 에이전트를 선택하는 방법을 배우고, 효율적인 팀 협업, 병렬 작업 실행, 깊이 있는 코드 분석을 가능하게 합니다.</p><h3 id="프로메테우스-계획-인터뷰-기반-요구사항-수집" tabindex="-1"><a href="./prometheus-planning/">프로메테우스 계획: 인터뷰 기반 요구사항 수집</a> <a class="header-anchor" href="#프로메테우스-계획-인터뷰-기반-요구사항-수집" aria-label="Permalink to &quot;[프로메테우스 계획: 인터뷰 기반 요구사항 수집](./prometheus-planning/)&quot;">​</a></h3><p>인터뷰 모드를 통해 요구사항을 명확화하고 작업 계획을 생성합니다. 프로메테우스는 요구사항이 명확해질 때까지 질문을 계속하고, 자동으로 오라클, 메티스, 모무스를 참조하여 계획 품질을 검증합니다.</p><h3 id="백그라운드-병렬-작업-팀처럼-작업하기" tabindex="-1"><a href="./background-tasks/">백그라운드 병렬 작업: 팀처럼 작업하기</a> <a class="header-anchor" href="#백그라운드-병렬-작업-팀처럼-작업하기" aria-label="Permalink to &quot;[백그라운드 병렬 작업: 팀처럼 작업하기](./background-tasks/)&quot;">​</a></h3><p>백그라운드 에이전트 관리 시스템 사용법을 심층적으로 설명합니다. 동시성 제어, 작업 폴링, 결과 검색을 배우고, 여러 AI 에이전트가 서로 다른 작업을 동시에 처리할 수 있게 하여 작업 효율을 극적으로 향상시킵니다.</p><h3 id="lsp-및-ast-grep-코드-리팩토링-도구" tabindex="-1"><a href="./lsp-ast-tools/">LSP 및 AST-Grep: 코드 리팩토링 도구</a> <a class="header-anchor" href="#lsp-및-ast-grep-코드-리팩토링-도구" aria-label="Permalink to &quot;[LSP 및 AST-Grep: 코드 리팩토링 도구](./lsp-ast-tools/)&quot;">​</a></h3><p>LSP 도구와 AST-Grep 도구 사용법을 소개합니다. 심볼 탐색, 참조 조회, 구조화된 코드 검색을 포함한 IDE 수준의 코드 분석 및 작업을 구현하는 방법을 보여줍니다.</p><h3 id="카테고리-및-스킬-동적-에이전트-구성" tabindex="-1"><a href="./categories-skills/">카테고리 및 스킬: 동적 에이전트 구성</a> <a class="header-anchor" href="#카테고리-및-스킬-동적-에이전트-구성" aria-label="Permalink to &quot;[카테고리 및 스킬: 동적 에이전트 구성](./categories-skills/)&quot;">​</a></h3><p>카테고리 및 스킬 시스템을 사용하여 전문화된 하위 에이전트를 만드는 방법을 배웁니다. 유연한 에이전트 구성을 구현하고, 작업 요구사항에 따라 모델, 도구, 스킬을 동적으로 할당합니다.</p><h3 id="내장-스킬-브라우저-자동화-및-git-전문가" tabindex="-1"><a href="./builtin-skills/">내장 스킬: 브라우저 자동화 및 Git 전문가</a> <a class="header-anchor" href="#내장-스킬-브라우저-자동화-및-git-전문가" aria-label="Permalink to &quot;[내장 스킬: 브라우저 자동화 및 Git 전문가](./builtin-skills/)&quot;">​</a></h3><p>세 가지 내장 스킬(playwright, frontend-ui-ux, git-master)의 사용 사례와 모범 사례를 상세히 소개합니다. 브라우저 자동화, 프론트엔드 UI 디자인, Git 작업과 같은 전문 기능에 빠르게 접근합니다.</p><h3 id="수명-주기-훅-자동화된-컨텍스트-및-품질-제어" tabindex="-1"><a href="./lifecycle-hooks/">수명 주기 훅: 자동화된 컨텍스트 및 품질 제어</a> <a class="header-anchor" href="#수명-주기-훅-자동화된-컨텍스트-및-품질-제어" aria-label="Permalink to &quot;[수명 주기 훅: 자동화된 컨텍스트 및 품질 제어](./lifecycle-hooks/)&quot;">​</a></h3><p>32개의 수명 주기 훅 사용법을 소개합니다. 컨텍스트 주입, 오류 복구, 품질 제어를 자동화하여 완전한 AI 워크플로우 자동화 시스템을 구축하는 방법을 이해합니다.</p><h3 id="슬래시-명령어-프리셋-워크플로우" tabindex="-1"><a href="./slash-commands/">슬래시 명령어: 프리셋 워크플로우</a> <a class="header-anchor" href="#슬래시-명령어-프리셋-워크플로우" aria-label="Permalink to &quot;[슬래시 명령어: 프리셋 워크플로우](./slash-commands/)&quot;">​</a></h3><p>6개의 내장 슬래시 명령어 사용법을 소개합니다. /ralph-loop(빠른 수정 루프), /refactor(코드 리팩토링), /start-work(프로젝트 실행 시작) 및 기타 일반적인 워크플로우를 포함합니다.</p><h3 id="구성-심층-사용자-정의-에이전트-및-권한-관리" tabindex="-1"><a href="./advanced-configuration/">구성 심층 사용자 정의: 에이전트 및 권한 관리</a> <a class="header-anchor" href="#구성-심층-사용자-정의-에이전트-및-권한-관리" aria-label="Permalink to &quot;[구성 심층 사용자 정의: 에이전트 및 권한 관리](./advanced-configuration/)&quot;">​</a></h3><p>에이전트 구성, 권한 설정, 모델 재정의, 프롬프트 수정의 심층 사용자 정의를 가르칩니다. 완전한 구성 기능을 마스터하고, 팀 표준에 부합하는 AI 워크플로우를 만듭니다.</p></div><h2 id="학습-경로" tabindex="-1">학습 경로 <a class="header-anchor" href="#학습-경로" aria-label="Permalink to &quot;학습 경로&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌─────────────────────────────────────────────────────────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│  Step 1                  Step 2                     Step 3                          Step 4                  │</span></span>
<span class="line"><span>│  Understand AI Agents  →   Master Planning     →   Learn Dynamic Agent     →   Deep Customization      │</span></span>
<span class="line"><span>│  (Basic Concepts)          &amp; Parallel Tasks         Composition                 &amp; Automation             │</span></span>
<span class="line"><span>│                                                      (Advanced Usage)          (Expert Level)           │</span></span>
<span class="line"><span>└─────────────────────────────────────────────────────────────────────────────────────────────────────────────┘</span></span></code></pre></div><p><strong>권장 순서</strong>:</p><ol><li><strong>AI 에이전트 팀으로 시작</strong>: 10명의 에이전트 책임과 사용 사례를 이해하세요—이것은 전체 시스템을 이해하는 기초입니다.</li><li><strong>그 다음 계획과 병렬 작업을 학습</strong>: 프로메테우스 계획과 백그라운드 작업 시스템을 마스터하세요—이것은 효율적인 협업의 핵심입니다.</li><li><strong>다음 동적 에이전트 구성을 학습</strong>: 카테고리와 스킬을 배워 유연한 에이전트 전문화를 달성합니다.</li><li><strong>마지막으로 심층 사용자 정의를 학습</strong>: 수명 주기 훅, 슬래시 명령어, 구성 사용자 정의를 마스터하여 완전한 워크플로우를 구축합니다.</li></ol><p><strong>고급 경로</strong>:</p><ul><li>목표가 <strong>빠른 시작</strong>인 경우: &quot;AI 에이전트 팀&quot;과 &quot;슬래시 명령어&quot;에 집중하세요</li><li>목표가 <strong>팀 협업</strong>인 경우: &quot;프로메테우스 계획&quot;과 &quot;백그라운드 병렬 작업&quot;을 깊이 파고들어보세요</li><li>목표가 <strong>워크플로우 자동화</strong>인 경우: &quot;수명 주기 훅&quot;과 &quot;구성 심층 사용자 정의&quot;를 학습하세요</li></ul><h2 id="전제-조건" tabindex="-1">전제 조건 <a class="header-anchor" href="#전제-조건" aria-label="Permalink to &quot;전제 조건&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">시작하기 전에</p><p>이 장은 다음을 완료했다고roid 가정합니다:</p><ul><li>✅ <a href="./../start/installation/">빠른 설치 및 구성</a>: oh-my-opencode를 설치하고 최소 하나의 Provider를 구성했습니다</li><li>✅ <a href="./../start/sisyphus-orchestrator/">시시푸스 첫 번째 보기: 메인 오케스트레이터</a>: 기본 에이전트 호출 및 위임 메커니즘을 이해했습니다</li><li>✅ <a href="./../platforms/provider-setup/">Provider 구성: Claude, OpenAI, Gemini</a>: 최소 하나의 AI Provider를 구성했습니다</li></ul></div><h2 id="다음-단계" tabindex="-1">다음 단계 <a class="header-anchor" href="#다음-단계" aria-label="Permalink to &quot;다음 단계&quot;">​</a></h2><p>이 장을 완료한 후, 다음을 계속하는 것을 권장합니다:</p><ul><li><strong><a href="./../faq/troubleshooting/">구성 진단 및 문제 해결</a></strong>: 문제가 발생할 때 빠르게 찾고 해결합니다.</li><li><strong><a href="./../appendix/configuration-reference/">구성 참조</a></strong>: 완전한 구성 파일 스키마를 보고 모든 구성 옵션을 이해합니다.</li><li><strong><a href="./../appendix/claude-code-compatibility/">Claude Code 호환성</a></strong>: 기존 Claude Code 워크플로우를 oh-my-opencode로 마이그레이션하는 방법을 배웁니다.</li></ul>`,15)])])}const g=e(s,[["render",i]]);export{u as __pageData,g as default};
